	legacySession := agent.SessionEntry{
		ID:           "as-legacy",
		Timestamp:    time.Date(2026, 4, 9, 9, 55, 0, 0, time.UTC),
		Harness:      "codex",
		Model:        "gpt-5.4",
		InputTokens:  120,
		OutputTokens: 12,
		CostUSD:      1.25,
		Duration:     1000,
