		CanonicalTarget: "gpt-5.4",
		Model:           "gpt-5.4",
		ObservedAt:      time.Date(2026, 4, 9, 10, 0, 1, 0, time.UTC),
		Success:         true,
		LatencyMS:       2000,
		InputTokens:     200,
		OutputTokens:    20,
		CostUSD:         2.50,
	}

	writeSessionIndex(t, dir, logDir, legacySession, currentSession)
