   215	func parseSince(s string) (time.Time, error) {
   216		switch s {
   217		case "today":
   218			now := time.Now()
   219			return time.Date(now.Year(), now.Month(), now.Day(), 0, 0, 0, 0, now.Location()), nil
   220		case "":
   221			return time.Now().AddDate(0, 0, -30), nil
   222		}
   223		if strings.HasSuffix(s, "d") {
   224			n, err := strconv.Atoi(strings.TrimSuffix(s, "d"))
