   274		}
   275		if maxBuckets > len(buckets) {
   276			maxBuckets = len(buckets)
   277		}
   278		total := 0
   279		for _, b := range buckets[len(buckets)-maxBuckets:] {
   280			total += b.Tokens
   281		}
   282		return total
   283	}
