   293	func refreshProviderStatuses(workDir string) {
   294		providerStatusCache.Lock()
   295		if providerStatusCache.inFlight[workDir] {
   296			providerStatusCache.Unlock()
   297			return
   298		}
   299		providerStatusCache.inFlight[workDir] = true
   300		providerStatusCache.Unlock()
   301	
   302		go func() {
   303			defer func() {
   304				providerStatusCache.Lock()
   305				delete(providerStatusCache.inFlight, workDir)
   306				providerStatusCache.Unlock()
   307			}()
   308			ctx, cancel := context.WithTimeout(context.Background(), 8*time.Second)
   309			defer cancel()
   310			providers, err := liveProviderInfos(ctx, workDir)
   311			if err != nil {
   312				return
   313			}
   314			rows := providerStatusesFromInfos(providers, nil, time.Now().UTC())
   315			storeProviderRows(workDir, rows)
   316		}()
   317	}
