   406	// buildSparkline returns a 24-element slice of hourly token totals for the
   407	// last 24 hours (oldest-first). Returns nil when fewer than 6 of the 24
   408	// hourly buckets have non-zero token counts — the UI uses that floor to
   409	// suppress noisy single-spike sparklines (FEAT-014 AC 2: "Sparkline renders
   410	// when ≥6 hourly buckets of usage are available").
   411	func buildSparkline(entries []agent.SessionIndexEntry, name string, kind agent.UsageMatchKind, now time.Time) []int {
   412		if len(entries) == 0 {
   413			return nil
   414		}
   415		buckets := agent.BucketUsage(entries, name, kind, now, 1, time.Hour)
   416		totals := make([]int, len(buckets))
   417		nonEmpty := 0
   418		for i, b := range buckets {
   419			totals[i] = b.Tokens
   420			if b.Tokens > 0 {
   421				nonEmpty++
   422			}
   423		}
   424		if nonEmpty < 6 {
   425			return nil
   426		}
   427		return totals
   428	}
   429	
   430	func cloneProviderRows(rows []*ProviderStatus) []*ProviderStatus {
   431		if len(rows) == 0 {
   432			return nil
   433		}
   434		out := make([]*ProviderStatus, 0, len(rows))
   435		for _, row := range rows {
   436			if row == nil {
   437				continue
   438			}
   439			clone := *row
   440			if row.DefaultForProfile != nil {
   441				clone.DefaultForProfile = append([]string(nil), row.DefaultForProfile...)
   442			}
   443			if row.Sparkline != nil {
   444				clone.Sparkline = append([]int(nil), row.Sparkline...)
   445			}
   446			out = append(out, &clone)
   447		}
   448		return out
   449	}
